patch:
diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 456f5086309c..2dcbca76936b 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -1122,10 +1122,16 @@ void State::addInfoFor(BasicBlock &BB) {
     }
     // Enqueue ssub_with_overflow for simplification.
     case Intrinsic::ssub_with_overflow:
+    case Intrinsic::usub_sat:
     case Intrinsic::ucmp:
     case Intrinsic::scmp:
       WorkList.push_back(
           FactOrCheck::getCheck(DT.getNode(&BB), cast<CallInst>(&I)));
+      if (ID == Intrinsic::usub_sat) {
+        if (!isGuaranteedNotToBePoison(&I))
+          break;
+        WorkList.push_back(FactOrCheck::getInstFact(DT.getNode(&BB), &I));
+      }
       break;
     // Enqueue the intrinsics to add extra info.
     case Intrinsic::umin:
@@ -1727,8 +1733,23 @@ tryToSimplifyOverflowMath(IntrinsicInst *II, ConstraintInfo &Info,
     if (!DoesConditionHold(CmpInst::ICMP_SGE, A, B, Info) ||
         !DoesConditionHold(CmpInst::ICMP_SGE, B,
                            ConstantInt::get(A->getType(), 0), Info))
-      return false;
     Changed = replaceSubOverflowUses(II, A, B, ToRemove);
+  } else if (II->getIntrinsicID() == Intrinsic::usub_sat) {
+    Value *A = II->getArgOperand(0);
+    Value *B = II->getArgOperand(1);
+    // If A u>= B, usub.sat(A, B) should not overflow and can be simplified to a regular sub.
+    if (DoesConditionHold(CmpInst::ICMP_UGE, A, B, Info)) {
+      IRBuilder<> Builder(II->getParent(), II->getIterator());
+      Value *Sub = Builder.CreateNUWSub(A, B, II->getName());
+      Sub->takeName(II);
+      II->replaceAllUsesWith(Sub);
+      ToRemove.push_back(II);
+      Changed = true;
+    } else if (DoesConditionHold(CmpInst::ICMP_ULE, A, B, Info)) {
+      II->replaceAllUsesWith(ConstantInt::get(II->getType(), 0));
+      ToRemove.push_back(II);
+      Changed = true;
+    }
   }
   return Changed;
 }

