  1712 |   auto DoesConditionHold = [](CmpInst::Predicate Pred, Value *A, Value *B,
  1713 |                               ConstraintInfo &Info) {
  1714 |     auto R = Info.getConstraintForSolving(Pred, A, B);
  1715 |     if (R.size() < 2 || !R.isValid(Info))
  1716 |       return false;
  1717 | 
  1718 |     auto &CSToUse = Info.getCS(R.IsSigned);
  1719 |     return CSToUse.isConditionImplied(R.Coefficients);
  1720 |   };
  1721 | 
  1722 |   bool Changed = false;
  1723 |   if (II->getIntrinsicID() == Intrinsic::ssub_with_overflow) {
  1724 |     // If A s>= B && B s>= 0, ssub.with.overflow(a, b) should not overflow and
  1725 |     // can be simplified to a regular sub.
  1726 |     Value *A = II->getArgOperand(0);
  1727 |     Value *B = II->getArgOperand(1);
  1728 |     if (!DoesConditionHold(CmpInst::ICMP_SGE, A, B, Info) ||
  1729 |         !DoesConditionHold(CmpInst::ICMP_SGE, B,
