cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/Scalar/ConstraintElimination.cpp 1732 1750
  } else if (II->getIntrinsicID() == Intrinsic::usub_sat) {
    Value *A = II->getArgOperand(0);
    Value *B = II->getArgOperand(1);
    // If A u>= B, usub.sat(A, B) should not overflow and can be simplified to a regular sub.
    if (DoesConditionHold(CmpInst::ICMP_UGE, A, B, Info)) {
      IRBuilder<> Builder(II->getParent(), II->getIterator());
      Value *Sub = Builder.CreateNUWSub(A, B, II->getName());
      Sub->takeName(II);
      II->replaceAllUsesWith(Sub);
      ToRemove.push_back(II);
      Changed = true;
    } else if (DoesConditionHold(CmpInst::ICMP_ULE, A, B, Info)) {
      II->replaceAllUsesWith(ConstantInt::get(II->getType(), 0));
      ToRemove.push_back(II);
      Changed = true;
    }
  }
  return Changed;
}
CODEEOF
EOF
sh /tmp/apply.sh"}

